// Auto-generated by r2factor. Manual edits will be overwritten on next split.

use super::super::types::DspChainOutput;
use ndarray::Array1;
use std::error::Error;

pub(super) fn same_frequency_grid(a: &[f64], b: &[f64]) -> bool {
    a.len() == b.len()
        && a.iter()
            .zip(b.iter())
            .all(|(&x, &y)| (x - y).abs() <= 1e-6 * x.abs().max(y.abs()).max(1.0))
}

const DISPLAY_MIN_FREQ: f64 = math_audio_iir_fir::AUDIBLE_MIN_FREQ;

const DISPLAY_MAX_FREQ: f64 = math_audio_iir_fir::AUDIBLE_MAX_FREQ;

/// Extend a curve's frequency range to cover 20 Hz – 20 kHz for display.
///
/// Points outside the measurement range are extrapolated using the local
/// log-frequency SPL slope at each boundary. The original measurement data
/// points are preserved.
pub fn extend_curve_to_full_range(curve: &crate::Curve) -> crate::Curve {
    if curve.freq.is_empty() {
        return curve.clone();
    }

    let meas_min = curve.freq[0];
    let meas_max = *curve.freq.last().unwrap();

    // If curve already approximately covers 20 Hz – 20 kHz, return as-is
    if meas_min <= DISPLAY_MIN_FREQ * 1.05 && meas_max >= DISPLAY_MAX_FREQ * 0.95 {
        return curve.clone();
    }

    let first_spl = curve.spl[0];
    let last_spl = *curve.spl.last().unwrap();
    let low_slope_ref = if curve.freq.len() >= 2 && curve.spl.len() >= 2 {
        Some((curve.freq[0], curve.spl[0], curve.freq[1], curve.spl[1]))
    } else {
        None
    };
    let high_slope_ref = if curve.freq.len() >= 2 && curve.spl.len() >= 2 {
        let last = curve.freq.len() - 1;
        Some((
            curve.freq[last - 1],
            curve.spl[last - 1],
            curve.freq[last],
            curve.spl[last],
        ))
    } else {
        None
    };
    let points_per_decade = 50;

    let mut freq_vec = Vec::new();
    let mut spl_vec = Vec::new();

    // Prepend log-spaced points from 20 Hz to first measurement frequency
    if meas_min > DISPLAY_MIN_FREQ * 1.05 {
        let log_start = DISPLAY_MIN_FREQ.log10();
        let log_end = meas_min.log10();
        let decades = log_end - log_start;
        let n_points = ((decades * points_per_decade as f64).ceil() as usize).max(1);
        for i in 0..n_points {
            let t = i as f64 / n_points as f64;
            let f = 10f64.powf(log_start + t * (log_end - log_start));
            freq_vec.push(f);
            spl_vec.push(
                low_slope_ref
                    .map(|(f0, spl0, f1, spl1)| extrapolate_spl_log_slope(f, f0, spl0, f1, spl1))
                    .unwrap_or(first_spl),
            );
        }
    }

    // Copy original data
    freq_vec.extend(curve.freq.iter());
    spl_vec.extend(curve.spl.iter());

    // Append log-spaced points from last measurement frequency to 20 kHz
    if meas_max < DISPLAY_MAX_FREQ * 0.95 {
        let log_start = meas_max.log10();
        let log_end = DISPLAY_MAX_FREQ.log10();
        let decades = log_end - log_start;
        let n_points = ((decades * points_per_decade as f64).ceil() as usize).max(1);
        for i in 1..=n_points {
            let t = i as f64 / n_points as f64;
            let f = 10f64
                .powf(log_start + t * (log_end - log_start))
                .min(DISPLAY_MAX_FREQ);
            freq_vec.push(f);
            spl_vec.push(
                high_slope_ref
                    .map(|(f0, spl0, f1, spl1)| extrapolate_spl_log_slope(f, f1, spl1, f0, spl0))
                    .unwrap_or(last_spl),
            );
        }
    }

    crate::Curve {
        freq: Array1::from(freq_vec),
        spl: Array1::from(spl_vec),
        phase: None,
        ..Default::default()
    }
}

fn extrapolate_spl_log_slope(
    freq: f64,
    boundary_freq: f64,
    boundary_spl: f64,
    neighbor_freq: f64,
    neighbor_spl: f64,
) -> f64 {
    if freq <= 0.0 || boundary_freq <= 0.0 || neighbor_freq <= 0.0 || boundary_freq == neighbor_freq
    {
        return boundary_spl;
    }

    let denom = neighbor_freq.log10() - boundary_freq.log10();
    if denom.abs() < 1e-12 {
        return boundary_spl;
    }

    let slope = (neighbor_spl - boundary_spl) / denom;
    boundary_spl + slope * (freq.log10() - boundary_freq.log10())
}

/// Get a descriptive name for a driver based on its index and total count
pub(super) fn get_driver_name(index: usize, n_drivers: usize) -> String {
    match (n_drivers, index) {
        (2, 0) => "woofer",
        (2, 1) => "tweeter",
        (3, 0) => "woofer",
        (3, 1) => "midrange",
        (3, 2) => "tweeter",
        (4, 0) => "woofer",
        (4, 1) => "lower_midrange",
        (4, 2) => "upper_midrange",
        (4, 3) => "tweeter",
        _ => return format!("driver_{}", index),
    }
    .to_string()
}

/// Save DSP chain to JSON file
pub fn save_dsp_chain(
    output: &DspChainOutput,
    path: &std::path::Path,
) -> Result<(), Box<dyn Error>> {
    let json = serde_json::to_string_pretty(output)?;
    std::fs::write(path, json)?;
    Ok(())
}
